</header>

<style lang="scss">
header nav {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    z-index: 10;
    padding: var(--sp-32) var(--sp-24);
	transition: var(--transition);
	transition-property: padding;
	pointer-events: none;
	
	&.dark { color: var(--black); }
	&.light { color: var(--white); }
	&.difference { color: var(--difference); mix-blend-mode: difference; }

	&.small {
		padding: var(--sp-16) var(--sp-24);
		
		.menu {
			.menu-left,
			.menu-right {
				margin-top: var(--sp-16);
			}
			.logo svg {
				height: 80px;
			}
		}
	}
    
    .menu {
        display: grid;
        grid-template-columns: 1fr auto 1fr; 
        align-items: flex-start;
        list-style: none;
        margin: 0;
        padding: 0;
        width: 100%;

		.menu-item {
			pointer-events: all;
		}

		.menu-left,
		.menu-right {
			display: flex;
			column-gap: var(--sp-20);
			transition: var(--transition);
			transition-property: margin-top, padding;
		}
        
        .menu-left {
            grid-column: 1;
			justify-content: flex-start;
        }

		 .menu-right {
            grid-column: 3;
            justify-content: flex-end;
        }

        .logo {
            grid-column: 2;
            display: flex;
            justify-content: center;

			svg {
				fill: currentColor;
				transition: var(--transition);
				height: 120px;
				padding-top: var(--sp-4);
				transition-property: height, padding-top;

				path {
					fill: currentColor;
				}
			}
        }
    }
}
</style>